helper_signature.function_definition:
def askBob(String prompt, String mode = null) {
    container('bob') {
        def promptFile = ".bob-prompt-${System.currentTimeMillis()}.txt"
        writeFile file: promptFile, text: prompt

        def modeFlag = mode ? "--chat-mode ${mode}" : ""
        def analysis = sh(
            script: """bob ${modeFlag} -p "\$(cat ${promptFile})" --hide-intermediary-output""",
            returnStdout: true
        ).trim()

        sh "rm -f ${promptFile}"
        return analysis
    }
}

pattern.example:
stage('PR Review') {
    steps {
        script {
            def prompt = "Review the changes in this PR for code quality and security."

            // Invoke Bob and capture output
            def analysis = askBob(prompt, 'solution-code-reviewer')

            // Display in console
            echo analysis
        }
    }
}

stage('PR Review') {
    steps {
        script {
            // Get diff content
            def diffContent = sh(
                script: 'git diff origin/main...HEAD',
                returnStdout: true
            ).trim()

            // Build prompt with diff
            def prompt = """
Review the following code changes for:
- Code quality and maintainability
- Security vulnerabilities
- Performance issues

Changes:
${diffContent}
"""

            // Invoke Bob
            def analysis = askBob(prompt, 'solution-code-reviewer')
            echo analysis
        }
    }
}

stage('PR Review') {
    steps {
        script {
            def prompt = "Review the changes in this PR."

            // Get Bob's analysis
            def analysis = askBob(prompt, 'solution-code-reviewer')

            // Save to file for archiving
            writeFile file: 'bob-pr-review.txt', text: analysis

            // Display in console
            echo analysis

            // Archive the analysis
            archiveArtifacts artifacts: 'bob-pr-review.txt',
                           allowEmptyArchive: true
        }
    }
}

stage('PR Review') {
    steps {
        script {
            catchError(buildResult: 'UNSTABLE', stageResult: 'FAILURE') {
                def prompt = "Review the changes in this PR."

                def analysis = askBob(prompt, 'solution-code-reviewer')

                // Save and archive
                writeFile file: 'bob-pr-review.txt', text: analysis
                echo analysis
                archiveArtifacts artifacts: 'bob-pr-review.txt',
                               allowEmptyArchive: true
            }
        }
    }
}

stage('PR Review') {
    steps {
        script {
            echo '════════════════════════════════════════════════════════'
            echo '  Bob PR Review Analysis'
            echo '════════════════════════════════════════════════════════'

            def prompt = "Review the changes in this PR."
            def analysis = askBob(prompt, 'solution-code-reviewer')

            echo analysis

            echo '════════════════════════════════════════════════════════'
            echo '  Bob PR Review Complete'
            echo '════════════════════════════════════════════════════════'

            // Archive
            writeFile file: 'bob-pr-review.txt', text: analysis
            archiveArtifacts artifacts: 'bob-pr-review.txt',
                           allowEmptyArchive: true
        }
    }
}

anti_pattern.bad:
// BAD: Direct bob CLI call
container('bob') {
    sh "bob --chat-mode solution-code-reviewer -p 'Review this'"
}

// BAD: Not capturing Bob's analysis
askBob(prompt, 'solution-code-reviewer')
// Analysis is lost!

anti_pattern.good:
// GOOD: Capture and use the analysis
def analysis = askBob(prompt, 'solution-code-reviewer')
echo analysis
writeFile file: 'bob-analysis.txt', text: analysis
